// MARK: - Promo Link Parser

class PromoLinkParser {
    
    static let supportedHost = "myapp.com"
    static let promoPath = "/promo"
    
    struct ParsedPromo {
        let code: String
        let discountPercentage: Int
        let additionalParams: [String: String]
    }
    
    static func parse(url: URL) -> Result<ParsedPromo, PromoError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        guard components.host == supportedHost,
              components.path == promoPath else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        let params = Dictionary(uniqueKeysWithValues: queryItems.compactMap { item -> (String, String)? in
            guard let value = item.value else { return nil }
            return (item.name, value)
        })
        
        guard let code = params["code"], !code.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        guard let discountString = params["discount"] else {
            return .failure(.missingDiscount)
        }
        
        guard let discount = Int(discountString), discount > 0, discount <= 100 else {
            return .failure(.invalidDiscount)
        }
        
        var additionalParams = params
        additionalParams.removeValue(forKey: "code")
        additionalParams.removeValue(forKey: "discount")
        
        return .success(ParsedPromo(
            code: code,
            discountPercentage: discount,
            additionalParams: additionalParams
        ))
    }
}

// MARK: - Promo Service

protocol PromoServiceProtocol {
    func validatePromoCode(_ code: String, discount: Int, completion: @escaping (Result<PromoCode, PromoError>) -> Void)
    func applyPromoCode(_ promoCode: PromoCode, toUserId userId: String, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void)
    func getUsedPromoCodes(forUserId userId: String) -> [String]
}

class PromoService: PromoServiceProtocol {
    
    static let shared = PromoService()
    
    private let usedPromoCodesKey = "usedPromoCodes"
    private let pendingPromoKey = "pendingPromoCode"
    private let userDefaults = UserDefaults.standard
    
    private init() {}
    
    func validatePromoCode(_ code: String, discount: Int, completion: @escaping (Result<PromoCode, PromoError>) -> Void) {
        // Simulate network validation - in production, call your backend API
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            
            // Simulated validation logic
            let promoCode = PromoCode(
                code: code.uppercased(),
                discountPercentage: discount,
                isValid: true,
                expirationDate: Calendar.current.date(byAdding: .month, value: 1, to: Date()),
                minimumPurchaseAmount: nil,
                maxUsageCount: 1000,
                currentUsageCount: 50
            )
            
            if promoCode.isExpired {
                DispatchQueue.main.async {
                    completion(.failure(.expiredPromo))
                }
                return
            }
            
            if promoCode.hasReachedUsageLimit {
                DispatchQueue.main.async {
                    completion(.failure(.usageLimitReached))
                }
                return
            }
            
            // Check if user already used this code
            let currentUserId = UserSessionManager.shared.currentUserId
            if let userId = currentUserId {
                let usedCodes = self.getUsedPromoCodes(forUserId: userId)
                if usedCodes.contains(code.uppercased()) {
                    DispatchQueue.main.async {
                        completion(.failure(.alreadyUsed))
                    }
                    return
                }
            }
            
            DispatchQueue.main.async {
                completion(.success(promoCode))
            }
        }
    }
    
    func applyPromoCode(_ promoCode: PromoCode, toUserId userId: String, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        // Simulate applying the promo code to the user's account via API
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            
            // Save to local storage that this code was used
            self.markPromoCodeAsUsed(promoCode.code, forUserId: userId)
            
            // Track analytics
            AnalyticsTracker.shared.trackPromoApplied(
                code: promoCode.code,
                discount: promoCode.discountPercentage,
                userId: userId
            )
            
            let result = PromoApplicationResult(
                success: true,
                message: "🎉 Promo code \(promoCode.code) applied! You got \(promoCode.discountPercentage)% off!",
                appliedDiscount: promoCode.discountPercentage,
                promoCode: promoCode.code
            )
            
            DispatchQueue.main.async {
                completion(.success(result))
            }
        }
    }
    
    func getUsedPromoCodes(forUserId userId: String) -> [String] {
        let key = "\(usedPromoCodesKey)_\(userId)"
        return userDefaults.stringArray(forKey: key) ?? []
    }
    
    func savePendingPromo(code: String, discount: Int) {
        let dict: [String: Any] = ["code": code, "discount": discount, "timestamp": Date().timeIntervalSince1970]
        userDefaults.set(dict, forKey: pendingPromoKey)
    }
    
    func getPendingPromo() -> (code: String, discount: Int)? {
        guard let dict = userDefaults.dictionary(forKey: pendingPromoKey),
              let code = dict["code"] as? String,
              let discount = dict["discount"] as? Int,
              let timestamp = dict["timestamp"] as? TimeInterval else {
            return nil
        }
        
        // Only return if the pending promo is less than 24 hours old
        let age = Date().timeIntervalSince1970 - timestamp
        guard age < 86400 else {
            clearPendingPromo()
            return nil
        }
        
        return (code, discount)
    }
    
    func clearPendingPromo() {
        userDefaults.removeObject(forKey: pendingPromoKey)
    }
    
    private func markPromoCodeAsUsed(_ code: String, forUserId userId: String) {
        let key = "\(usedPromoCodesKey)_\(userId)"
        var usedCodes = userDefaults.stringArray(forKey: key) ?? []
        usedCodes.append(code.uppercased())
        userDefaults.set(usedCodes, forKey: key)
    }
}

// MARK: - User Session Manager

class UserSessionManager {
    static let shared = UserSessionManager()
    
    var currentUserId: String? {
        return UserDefaults.standard.string(forKey: "currentUserId")
    }
    
    var isLoggedIn: Bool {
        return currentUserId != nil
    }
    
    func login(userId: String) {
        UserDefaults.standard.set(userId, forKey: "currentUserId")
        NotificationCenter.default.post(name: .userDidLogin, object: nil)
    }
    
    func logout() {
        UserDefaults.standard.removeObject(forKey: "currentUserId")
        NotificationCenter.default.post(name: .userDidLogout, object: nil)
    }
}

