// MARK: - Deep Link Handler

class DeepLinkHandler {
    
    static let shared = DeepLinkHandler()
    
    private let promoService = PromoService.shared
    private let sessionManager = UserSessionManager.shared
    
    weak var presentingViewController: UIViewController?
    
    private init() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleUserLogin),
            name: .userDidLogin,
            object: nil
        )
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        let result = PromoLinkParser.parse(url: url)
        
        switch result {
        case .success(let parsedPromo):
            handlePromo(code: parsedPromo.code, discount: parsedPromo.discountPercentage, additionalParams: parsedPromo.additionalParams)
            return true
        case .failure(let error):
            AnalyticsTracker.shared.trackPromoFailed(code: url.absoluteString, reason: error.localizedDescription ?? "Unknown error")
            showError(error)
            return false
        }
    }
    
    func handlePromo(code: String, discount: Int, additionalParams: [String: String] = [:]) {
        let source = additionalParams["utm_source"] ?? "direct"
        AnalyticsTracker.shared.trackPromoLinkOpened(code: code, discount: discount, source: source)
        
        guard sessionManager.isLoggedIn else {
            // Save pending promo and prompt login
            promoService.savePendingPromo(code: code, discount: discount)
            showLoginPrompt(promoCode: code, discount: discount)
            return
        }
        
        validateAndApplyPromo(code: code, discount: discount)
    }
    
    private func validateAndApplyPromo(code: String, discount: Int) {
        guard let userId = sessionManager.currentUserId else {
            showError(.userNotLoggedIn)
            return
        }
        
        showLoadingIndicator()
        
        promoService.validatePromoCode(code, discount: discount) { [weak self] result in
            self?.hideLoadingIndicator()
            
            switch result {
            case .success(let promoCode):
                self?.applyPromoToAccount(promoCode, userId: userId)
            case .failure(let error):
                AnalyticsTracker.shared.trackPromoFailed(code: code, reason: error.localizedDescription ?? "Unknown")
                self?.showError(error)
            }
        }
    }
    
    private func applyPromoToAccount(_ promoCode: PromoCode, userId: String) {
        showLoadingIndicator()
        
        promoService.applyPromoCode(promoCode, toUserId: userId) { [weak self] result in
            self?.hideLoadingIndicator()
            
            switch result {
            case .success(let applicationResult):
                self?.promoService.clearPendingPromo()
                self?.showPromoSuccess(applicationResult)
                NotificationCenter.default.post(
                    name: .promoCodeApplied,
                    object: nil,
                    userInfo: [
                        "code": promoCode.code,
                        "discount": promoCode.discountPercentage
                    ]
                )
            case .failure(let error):
                AnalyticsTracker.shared.trackPromoFailed(code: promoCode.code, reason: error.localizedDescription ?? "Unknown")
                self?.showError(error)
            }
        }
    }
    
    @objc private func handleUserLogin() {
        // Check for pending promo after login
        if let pending = promoService.getPendingPromo() {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
                self?.validateAndApplyPromo(code: pending.code, discount: pending.discount)
            }
        }
    }
    
    // MARK: - UI Helpers
    
    private func showPromoSuccess(_ result: PromoApplicationResult) {
        guard let vc = presentingViewController ?? topViewController() else { return }
        
        let alert = UIAlertController(
            title: "Promo Applied!",
            message: result.message,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Awesome!", style: .default))
        vc.present(alert, animated: true)
    }
    
    private func showError(_ error: PromoError) {
        guard let vc = presentingViewController ?? topViewController() else { return }
        
        let alert = UIAlertController(
            title: "Promo Error",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        vc.present(alert, animated: true)
    }
    
    private func showLoginPrompt(promoCode: String, discount: Int) {
        guard let vc = presentingViewController ?? topViewController() else { return }
        
        let alert = UIAlertController(
            title: "Log In Required",
            message: "Please log in to apply promo code \(promoCode) for \(discount)% off! Your promo will be applied automatically after login.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Log In", style: .default) { _ in
            // Navigate to login screen
            NotificationCenter.default.post(name: Notification.Name("showLogin"), object: nil)
        })
        alert.addAction(UIAlertAction(title: "Later", style: .cancel))
        vc.present(alert, animated: true)
    }
    
    private func showLoadingIndicator() {
        // Show loading UI
    }
    
    private func hideLoadingIndicator() {
        // Hide loading UI
    }
    
    private func topViewController() -> UIViewController? {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first(where: { $0.isKeyWindow }) else {
            return nil
        }
        
        var topController = window.rootViewController
        while let presented = topController?.presentedViewController {
            topController = presented
        }
        return topController
    }
}

