    private let testLinkButton = UIButton(type: .system)
    private var promoBanner: PromoBannerView?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupNotifications()
        updateUIForLoginState()
        
        DeepLinkHandler.shared.presentingViewController = self
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "My App"
        
        statusLabel.font = .systemFont(ofSize: 18, weight: .medium)
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        
        promoInfoLabel.font = .systemFont(ofSize: 14)
        promoInfoLabel.textAlignment = .center
        promoInfoLabel.numberOfLines = 0
        promoInfoLabel.textColor = .secondaryLabel
        
        loginButton.setTitle("Simulate Login", for: .normal)
        loginButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        loginButton.addTarget(self, action: #selector(loginTapped), for: .touchUpInside)
        
        logoutButton.setTitle("Logout", for: .normal)
        logoutButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        logoutButton.setTitleColor(.systemRed, for: .normal)
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
        
        testLinkButton.setTitle("Test Promo Link", for: .normal)
        testLinkButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        testLinkButton.backgroundColor = .systemBlue
        testLinkButton.setTitleColor(.white, for: .normal)
        testLinkButton.layer.cornerRadius = 8
        testLinkButton.addTarget(self, action: #selector(testLinkTapped), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [statusLabel, promoInfoLabel, loginButton, logoutButton, testLinkButton])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.alignment = .center
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            testLinkButton.widthAnchor.constraint(equalTo: stackView.widthAnchor),
            testLinkButton.heightAnchor.constraint(equalToConstant: 50),
        ])
    }
    
    private func setupNotifications() {
        NotificationCenter.default.addObserver(self, selector: #selector(promoApplied(_:)), name: .promoCodeApplied, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(showLoginScreen), name: Notification.Name("showLogin"), object: nil)
    }
    
    private func updateUIForLoginState() {
        let isLoggedIn = UserSessionManager.shared.isLoggedIn
        loginButton.isHidden = isLoggedIn
        logoutButton.isHidden = !isLoggedIn
        
        if isLoggedIn {
            statusLabel.text = "Logged in as: \(UserSessionManager.shared.currentUserId ?? "Unknown")"
        } else {
            statusLabel.text = "Not logged in"
        }
        
        // Show used promo codes
        if let userId = UserSessionManager.shared.currentUserId {
            let usedCodes = PromoService.shared.getUsedPromoCodes(forUserId: userId)
            if !usedCodes.isEmpty {
                promoInfoLabel.text = "Applied promos: \(usedCodes.joined(separator: ", "))"
            } else {
                promoInfoLabel.text = "No promo codes applied yet"
            }
        } else {
            promoInfoLabel.text = ""
        }
    }
    
    func showPromoBanner(code: String, discount: Int) {
        promoBanner?.removeFromSuperview()
        
        let banner = PromoBannerView()
        banner.configure(code: code, discount: discount)
        banner.translatesAutoresizingMaskIntoConstraints = false
        
        banner.onApply = { [weak self] in
            DeepLinkHandler.shared.handlePromo(code: code, discount: discount)
            self?.hidePromoBanner()
        }
        
        banner.onDismiss = { [weak self] in
            self?.hidePromoBanner()
        }
        
        view.addSubview(banner)
        
        NSLayoutConstraint.activate([
            banner.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            banner.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            banner.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
        ])
        
        banner.alpha = 0
        banner.transform = CGAffineTransform(translationX: 0, y: 100)
        
        UIView.animate(withDuration: 0.4, delay: 0, usingSpringWithDamping: 0.8, initialSpringVelocity: 0, options: .curveEaseOut) {
            banner.alpha = 1
            banner.transform = .identity
        }
        
        self.promoBanner = banner
    }
    
    private func hidePromoBanner() {
        UIView.animate(withDuration: 0.3, animations: {
            self.promoBanner?.alpha = 0
            self.promoBanner?.transform = CGAffineTransform(translationX: 0, y: 100)
        }) { _ in
            self.promoBanner?.removeFromSuperview()
            self.promoBanner = nil
        }
    }
    
    @objc private func loginTapped() {
        let alert = UIAlertController(title: "Login", message: "Enter a user ID", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "User ID"
            textField.text = "user123"
        }
        alert.addAction(UIAlertAction(title: "Login", style: .default) { [weak self] _ in
            let userId = alert.textFields?.first?.text ?? "user123"
            UserSessionManager.shared.login(userId: userId)
            self?.updateUIForLoginState()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func logoutTapped() {
        UserSessionManager.shared.logout()
        updateUIForLoginState()
    }
    
    @objc private func testLinkTapped() {
        let testURL = URL(string: "https://myapp.com/promo?code=SUMMER2024&discount=50&utm_source=test")!
        _ = DeepLinkHandler.shared.handleUniversalLink(testURL)
    }
    
    @objc private func promoApplied(_ notification: Notification) {
        updateUIForLoginState()
    }
    
    @objc private func showLoginScreen() {
        loginTapped()
    }
    
    deinit {
        NotificationCenter.default.removeObserver(self)
    }
}

// MARK: - Scene Delegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let mainVC = MainViewController()
        let navController = UINavigationController(rootViewController: mainVC)
        window.rootViewController = navController
        self.window = window
        window.makeKeyAndVisible()
        
        // Handle universal links from cold launch
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            _ = DeepLinkHandler.shared.handleUniversalLink(url)
        }
        
        // Handle URL contexts (e.g., from URL schemes)
        if let urlContext = connectionOptions.urlContexts.first {
            _ = DeepLinkHandler.shared.handleUniversalLink(urlContext.url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        _ = DeepLinkHandler.shared.handleUniversalLink(url)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        _ = DeepLinkHandler.shared.handleUniversalLink(url)
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let configuration = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        configuration.delegateClass = SceneDelegate.self
        return configuration
    }
    
    // Handle universal links for iOS 12 and below compatibility
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return DeepLinkHandler.shared.handleUniversalLink(url)
    }
}